export interface BluetoothManager {
  GetState(request: CBluetoothManagerGetStateRequest): Promise<CBluetoothManagerGetStateResponse>;
  GetAdapterDetails(
    request: CBluetoothManagerGetAdapterDetailsRequest,
  ): Promise<CBluetoothManagerGetAdapterDetailsResponse>;
  GetDeviceDetails(
    request: CBluetoothManagerGetDeviceDetailsRequest,
  ): Promise<CBluetoothManagerGetDeviceDetailsResponse>;
  NotifyStateChanged(request: CBluetoothManagerStateChangedNotification): Promise<WebUINoResponse>;
  SetDiscovering(request: CBluetoothManagerSetDiscoveringRequest): Promise<CBluetoothManagerSetDiscoveringResponse>;
  SetLoginAdvertising(
    request: CBluetoothManagerSetLoginAdvertisingRequest,
  ): Promise<CBluetoothManagerSetLoginAdvertisingResponse>;
  Pair(request: CBluetoothManagerPairRequest): Promise<CBluetoothManagerPairResponse>;
  CancelPair(request: CBluetoothManagerCancelPairRequest): Promise<CBluetoothManagerCancelPairResponse>;
  Forget(request: CBluetoothManagerForgetRequest): Promise<CBluetoothManagerForgetResponse>;
  Connect(request: CBluetoothManagerConnectRequest): Promise<CBluetoothManagerConnectResponse>;
  Disconnect(request: CBluetoothManagerDisconnectRequest): Promise<CBluetoothManagerDisconnectResponse>;
  SetWakeAllowed(request: CBluetoothManagerSetWakeAllowedRequest): Promise<CBluetoothManagerSetWakeAllowedResponse>;
  SetTrusted(request: CBluetoothManagerSetTrustedRequest): Promise<CBluetoothManagerSetTrustedResponse>;
}

function longToNumber(int64: { toString(): string }): number {
  const num = globalThis.Number(int64.toString());
  if (num > globalThis.Number.MAX_SAFE_INTEGER) {
    throw new globalThis.Error("Value is larger than Number.MAX_SAFE_INTEGER");
  }
  if (num < globalThis.Number.MIN_SAFE_INTEGER) {
    throw new globalThis.Error("Value is smaller than Number.MIN_SAFE_INTEGER");
  }
  return num;
}

interface MessageFns<T> {
  encode(message: T, writer?: BinaryWriter): BinaryWriter;
  decode(input: BinaryReader | Uint8Array, length?: number): T;
}
